// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.20;

import {Initializable} from "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import {UUPSUpgradeable} from "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import {OwnableUpgradeable} from "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import {EnumerableSet} from "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";

/// @title DataConsent 
/// @notice Upgradeable smart contract to track user-granted data consent to companies
/// @dev Uses UUPS proxy pattern and EnumerableSet for O(1) loop-free access checks
contract DataConsent is Initializable, UUPSUpgradeable, OwnableUpgradeable {
    using EnumerableSet for EnumerableSet.AddressSet;

    /// @notice Optimized Struct (fits into fewer storage slots)
    struct DataRecord {
        string dataHash;
        address owner;
        uint64 timestamp;
        bool active;
    }
    
    mapping(address => DataRecord) public records;
    
    // Mapping from data owner => set of authorized companies
    mapping(address => EnumerableSet.AddressSet) private authorizedCompanies;

    // Mapping from data owner => company => status (0: None, 1: Pending, 2: Approved)
    mapping(address => mapping(address => uint8)) public accessRequests; 

    // Custom Errors
    error DataAlreadyRegistered(address owner);
    error RecordNotActive(address owner);
    error UserAlreadyAuthorized(address owner, address user);
    error AccessAlreadyRequested(address owner, address company);
    error NoPendingRequestForCompany(address owner, address company);
    error UserNotFoundInAuthorizedList(address owner, address user);

    // Events
    event ConsentRegistered(address indexed owner, string dataHash, uint64 timestamp);
    event AccessGranted(address indexed owner, address indexed authorizedUser, uint64 timestamp);
    event AccessRevoked(address indexed owner, address indexed revokedUser, uint64 timestamp);
    event AccessRequested(address indexed owner, address indexed company);
    event RequestApproved(address indexed owner, address indexed company);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    /// @notice Initializes the proxy contract
    function initialize(address initialOwner) initializer public {
        __Ownable_init(initialOwner);
        __UUPSUpgradeable_init();
    }

    /// @notice Reverts if the sender does not have an active record
    modifier onlyActiveRecord(address _owner) {
        if (!records[_owner].active) revert RecordNotActive(_owner);
        _;
    }

    /// @notice Returns data record and an array of authorized users 
    function getRecordByOwner(address _owner) public view returns (
        string memory dataHash, 
        address owner, 
        address[] memory authorizedUsers, 
        uint64 timestamp, 
        bool active
    ) {
        DataRecord storage recordData = records[_owner];
        return (
            recordData.dataHash, 
            recordData.owner, 
            authorizedCompanies[_owner].values(), 
            recordData.timestamp, 
            recordData.active
        );
    }

    /// @notice Registers initial data for a user
    function registerData(string memory _dataHash, address[] memory _initialAuthorizedUsers) public {
        if (records[msg.sender].active) revert DataAlreadyRegistered(msg.sender);
        
        records[msg.sender] = DataRecord({
            dataHash: _dataHash, 
            owner: msg.sender, 
            timestamp: uint64(block.timestamp), 
            active: true
        });
        
        for (uint i = 0; i < _initialAuthorizedUsers.length; i++) {
            authorizedCompanies[msg.sender].add(_initialAuthorizedUsers[i]);
            emit AccessGranted(msg.sender, _initialAuthorizedUsers[i], uint64(block.timestamp));
        }

        emit ConsentRegistered(msg.sender, _dataHash, uint64(block.timestamp));
    }

    /// @notice Authorizes a single company
    function authorizeAccess(address user) public onlyActiveRecord(msg.sender) {
        bool added = authorizedCompanies[msg.sender].add(user);
        if (!added) revert UserAlreadyAuthorized(msg.sender, user);

        emit AccessGranted(msg.sender, user, uint64(block.timestamp));
    }

    /// @notice Requested by a company to gain access to user data
    function requestAccess(address _owner) public onlyActiveRecord(_owner) {
        if (accessRequests[_owner][msg.sender] != 0) revert AccessAlreadyRequested(_owner, msg.sender);

        accessRequests[_owner][msg.sender] = 1; // 1 = Pending
        emit AccessRequested(_owner, msg.sender);
    }

    /// @notice Approved by the user for a pending request
    function approveRequest(address _company) public onlyActiveRecord(msg.sender) {
        if (accessRequests[msg.sender][_company] != 1) revert NoPendingRequestForCompany(msg.sender, _company);

        accessRequests[msg.sender][_company] = 2; // 2 = Approved
        authorizeAccess(_company);

        emit RequestApproved(msg.sender, _company);
    }

    /// @notice Revokes a company's access to user data
    function revokeAccess(address user) public onlyActiveRecord(msg.sender) {
        bool removed = authorizedCompanies[msg.sender].remove(user);
        if (!removed) revert UserNotFoundInAuthorizedList(msg.sender, user);
        
        if(accessRequests[msg.sender][user] == 2) {
            accessRequests[msg.sender][user] = 0;
        }

        emit AccessRevoked(msg.sender, user, uint64(block.timestamp));
    }

    /// @dev Required by UUPS, limits upgrade access strictly to the owner of the proxy
    function _authorizeUpgrade(address newImplementation) internal onlyOwner override {}
}

